import psycopg2

def search_users(username=None, email=None, role=None, status=None):
    conn = psycopg2.connect("dbname=your_db user=your_user password=your_password host=your_host")
    cur = conn.cursor()
    
    query_parts = ['SELECT * FROM users']
    params = []
    
    if username:
        query_parts.append('WHERE username LIKE %s')
        params.append(f'%{username}%')
    
    if email:
        if 'WHERE' in query_parts[1:]:
            query_parts.append('AND')
        else:
            query_parts.append('WHERE')
        query_parts.append('email LIKE %s')
        params.append(f'%{email}%')
    
    if role:
        if 'WHERE' in query_parts[1:]:
            query_parts.append('AND')
        else:
            query_parts.append('WHERE')
        query_parts.append('role = %s')
        params.append(role)
    
    if status:
        if 'WHERE' in query_parts[1:]:
            query_parts.append('AND')
        else:
            query_parts.append('WHERE')
        query_parts.append('status = %s')
        params.append(status)
    
    full_query = ' '.join(query_parts)
    cur.execute(full_query, params)
    
    results = cur.fetchall()
    cur.close()
    conn.close()
    
    return results

# Example usage
users = search_users(username='john', role='admin', status='active')
print(users)